using System.ComponentModel;
using Microsoft.Extensions.AI;
using OpenAI;

Console.WriteLine("Research Agent Starting...");
Console.WriteLine("=".PadRight(50, '='));

// Configure the AI client
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "your-api-key";
var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// Initialize the note-taking storage
var researchNotes = new ResearchNotes();

// Register tools
var tools = new List<AITool>
{
    AIFunctionFactory.Create(researchNotes.AddNote),
    AIFunctionFactory.Create(researchNotes.GetAllNotes),
    AIFunctionFactory.Create(WebSearchTool.Search),
};

var chatOptions = new ChatOptions { Tools = tools };

// Get topic from user
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}");
Console.WriteLine("-".PadRight(50, '-'));

// Build the agent system prompt
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to research a given topic thoroughly.

        Follow this process:
        1. Search the web for information about the topic using multiple queries
        2. Save important findings as notes using the note-taking tool
        3. After gathering enough information, retrieve all your notes
        4. Provide a comprehensive summary of your research findings

        Be thorough — perform at least 3 different searches to cover various aspects of the topic.
        Save at least one note per search with key findings.
        End with a clear, well-structured summary.
        """),
    new(ChatRole.User, $"Please research the following topic: {topic}")
};

// Run the agent loop
Console.WriteLine("\nAgent is working...\n");

var response = await chatClient.GetResponseAsync(messages, chatOptions);
Console.WriteLine("\n" + "=".PadRight(50, '='));
Console.WriteLine("RESEARCH COMPLETE");
Console.WriteLine("=".PadRight(50, '='));
Console.WriteLine(response.Text);

// --- Tool Definitions ---

/// <summary>Simulates web search functionality.</summary>
static class WebSearchTool
{
    [Description("Search the web for information. Returns a list of relevant results with titles and snippets.")]
    public static string Search([Description("The search query string")] string query)
    {
        // In a real implementation, this would call a search API (e.g., Bing Search API).
        // Here we simulate results to demonstrate the agent pattern.
        Console.WriteLine($"  [Tool] Web Search: \"{query}\"");

        return $"""
            Search results for: "{query}"

            1. Title: "Comprehensive Overview of {query}"
               Snippet: This article provides a detailed overview covering the history, 
               current state, and future developments related to {query}. Key points include 
               recent advances and notable contributions to the field.
               Source: research-journal.example.com

            2. Title: "{query} - Latest Developments 2026"
               Snippet: The latest developments in {query} show significant progress. 
               Experts predict major breakthroughs in the coming years. Multiple organizations 
               are investing heavily in this area.
               Source: tech-news.example.com

            3. Title: "Understanding {query}: A Practical Guide"
               Snippet: A practical guide explaining the fundamentals of {query}, including 
               real-world applications, challenges, and opportunities for practitioners 
               and researchers alike.
               Source: developer-guides.example.com
            """;
    }
}

/// <summary>Note-taking tool for the research agent to store findings.</summary>
class ResearchNotes
{
    private readonly List<string> _notes = [];

    [Description("Save a research note with key findings. Use this to record important information discovered during research.")]
    public string AddNote(
        [Description("The content of the note to save")] string content,
        [Description("A short label or category for the note")] string label = "General")
    {
        _notes.Add($"[{label}] {content}");
        Console.WriteLine($"  [Tool] Note saved: [{label}] {content[..Math.Min(60, content.Length)]}...");
        return $"Note saved successfully. Total notes: {_notes.Count}";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public string GetAllNotes()
    {
        Console.WriteLine($"  [Tool] Retrieving {_notes.Count} notes");
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        return "Saved research notes:\n" +
               string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
    }
}

